arguments.spec:
{
  "kind": "hypothesis_panel",
  "title": "Flux-Core Porosity — Ranked Checks",
  "primarySymptom": "Porosity / pinholes in self-shielded flux-core bead",
  "hypotheses": [
    {
      "id": "polarity",
      "label": "Polarity reversed — must be DCEN for gasless flux-core",
      "likelihood": "high",
      "rationale": "Wrong polarity is the most common cause of severe porosity + heavy spatter with self-shielded wire.",
      "checkAction": "Power off. Confirm Ground Clamp is in the POSITIVE (+) socket and Wire Feed Power cable is in the NEGATIVE (–) socket. Twist clockwise to lock.",
      "citations": [{"source": "owner-manual.pdf", "page": 13, "section": "DCEN Wire Setup for Flux-Cored (gasless)"}]
    },
    {
      "id": "dirty-workpiece",
      "label": "Dirty workpiece (mill scale, paint, rust, oil, moisture)",
      "likelihood": "high",
      "rationale": "Manual lists dirty workpiece as a primary porosity cause. Self-shielded flux tolerates some contamination but not paint, galvanizing, or heavy rust.",
      "checkAction": "Grind or wire-brush the joint to bright metal ~1 inch back from the weld line on both sides. Wipe off oil/moisture.",
      "citations": [
        {"source": "owner-manual.pdf", "page": 37, "section": "Wire Weld – Porosity"},
        {"source": "owner-manual.pdf", "page": 43, "section": "Porosity in the Weld Metal"}
      ]
    },
    {
      "id": "ctwd",
      "label": "Gun too far from work / stickout too long",
      "likelihood": "medium-high",
      "rationale": "Excess CTWD lets air reach the arc before the flux vapor curtain forms.",
      "checkAction": "Keep contact-tip-to-work distance around 3/8\"–3/4\" (general practice).",
      "citations": [
        {"source": "owner-manual.pdf", "page": 37, "section": "Wire Weld – Porosity"},
        {"source": "owner-manual.pdf", "page": 43, "section": "Porosity in the Weld Metal"}
      ]
    },
    {
      "id": "dirty-wire",
      "label": "Dirty / rusted / moisture-contaminated wire",
      "likelihood": "medium",
      "rationale": "Flux-core wire absorbs moisture if left uncovered; contaminated wire introduces porosity.",
      "checkAction": "Inspect spool for rust/discoloration. If suspect, cut back 6–12\" or replace the spool. Store sealed with desiccant.",
      "citations": [{"source": "owner-manual.pdf", "page": 43, "section": "Porosity in the Weld Metal"}]
    },
    {
      "id": "travel-speed",
      "label": "Inconsistent travel speed",
      "likelihood": "medium",
      "rationale": "Manual lists inconsistent travel speed under Wire Weld – Porosity.",
      "checkAction": "Maintain a steady pace; adjust based on bead profile.",
      "citations": [{"source": "owner-manual.pdf", "page": 37, "section": "Wire Weld – Porosity"}]
    }
  ],
  "ruledOut": [
    {
      "label": "Shielding gas bottle empty / flow wrong",
      "reason": "Self-shielded flux-core uses no external gas. Manual p.37 notes 'insufficient shielding gas (MIG only)'."
    }
  ]
}

{
  "type": "checklist",
  "title": "Flux-Core Porosity — What to Check First",
  "items": [
    {
      "label": "Verify polarity is DCEN: Ground → (+) socket, Wire Feed cable → (–) socket",
      "citation": "owner-manual.pdf p.13"
    },
    {
      "label": "Clean workpiece to bright metal (remove paint, rust, oil, mill scale)",
      "citation": "owner-manual.pdf p.37, p.43"
    },
    {
      "label": "Reduce contact-tip-to-work distance (stickout ~3/8\"–3/4\")",
      "citation": "owner-manual.pdf p.37, p.43"
    },
    {
      "label": "Inspect wire spool for rust or moisture; cut back or replace if suspect",
      "citation": "owner-manual.pdf p.43"
    },
    {
      "label": "Maintain steady travel speed",
      "citation": "owner-manual.pdf p.37"
    }
  ]
}
